SELECT 
  (SELECT COUNT(*) FROM publishers) AS total_publishers,
  (SELECT AVG(strftime('%Y', 'now') - strftime('%Y', birthdate)) FROM authors) AS average_author_age;

SELECT text_id, AVG(LENGTH(excerpt_text)) AS average_excerpt_length
FROM excerpts
GROUP BY text_id;

SELECT title
FROM texts
WHERE word_count = (
    SELECT MAX(word_count)
    FROM texts
);

SELECT name 
FROM authors 
WHERE author_id = (SELECT author_id FROM texts WHERE text_id = 1);

SELECT permission_id
FROM user_role_permissions
WHERE role_id = 1;
